#!/usr/bin/env perl
#Author: ALin
#Purpose: To convert the *_merged_id.txt file generated by isoPropeller_merge_* to pairs Transcript_id and Original_id.
#Usage: perl merged_id2original_id.pl <input> <output>

use strict;

if(@ARGV != 2){
	print "Usage: perl merged_id2original_id.pl <input> <output>\n";
	exit;
}

my ($in, $out) = @ARGV;

open(IN, $in) or die "Cannot open $in!\n";
open(OUT, "> $out") or die "Cannot create $out!\n";

print OUT "transcript_id\t#isoform\n";

my $header = 0;
my %header = ();

while(<IN>){
	chomp;
	my $line = $_;
	$line =~ s/\r//;
	my @line = split('\t', $line);
	if($header == 0){
		my $num_col = @line;
		for(my $i = 0; $i < $num_col; $i++){
			if(exists $header{$line[$i]}){
				print "Duplicated column $line[$i]!\n";
				exit;
			}
			else{
				$header{$line[$i]} = $i;
			}
		}
		$header = 1;
		next;
	}
	my @oid = split(',', $line[$header{'original_id'}]);
	foreach my $oid (@oid){
		print OUT "$line[$header{'transcript_id'}]\t$oid\n";
	}
}
close IN;
close OUT;


